import React, { useState } from 'react'
import { toast } from 'react-hot-toast'
import { 
  Download, 
  Upload, 
  Database, 
  FileText, 
  Settings, 
  Users, 
  Package,
  IndianRupee,
  Calendar,
  AlertTriangle,
  CheckCircle,
  RefreshCw,
  FolderOpen,
  Archive
} from 'lucide-react'

const SiteBackup = () => {
  const [isExporting, setIsExporting] = useState(false)
  const [isImporting, setIsImporting] = useState(false)
  const [importFile, setImportFile] = useState(null)
  const [exportProgress, setExportProgress] = useState(0)
  const [importProgress, setImportProgress] = useState(0)
  const [isDbExporting, setIsDbExporting] = useState(false)
  const [isSettingsExporting, setIsSettingsExporting] = useState(false)

  // Define all page files to backup
  const pageFiles = [
    // Main pages
    { name: 'Dashboard.jsx', path: 'src/pages/Dashboard.jsx', type: 'page', icon: Database },
    { name: 'Customers.jsx', path: 'src/pages/Customers.jsx', type: 'page', icon: Users },
    { name: 'CustomerManagement', path: 'src/pages/CustomerManagement/', type: 'folder', icon: Users },
    { name: 'Settings', path: 'src/pages/Settings/', type: 'folder', icon: Settings },
    { name: 'ReminderManagement', path: 'src/pages/ReminderManagement/', type: 'folder', icon: Calendar },
    { name: 'ExpenseSettings.jsx', path: 'src/pages/ExpenseSettings.jsx', type: 'page', icon: IndianRupee },
    
    // Components
    { name: 'Components', path: 'src/components/', type: 'folder', icon: Package },
    
    // Services/API
    { name: 'Services API', path: 'src/services/api.js', type: 'api', icon: Settings },
    { name: 'Settings API', path: 'src/services/settingsAPI.js', type: 'api', icon: Settings },
    { name: 'Staff API', path: 'src/services/staffAPI.js', type: 'api', icon: Users },
    
    // Configuration files
    { name: 'package.json', path: 'package.json', type: 'config', icon: FileText },
    { name: 'vite.config.js', path: 'vite.config.js', type: 'config', icon: Settings },
    { name: 'tailwind.config.js', path: 'tailwind.config.js', type: 'config', icon: Settings },
    { name: 'App.jsx', path: 'src/App.jsx', type: 'page', icon: Database },
    { name: 'main.jsx', path: 'src/main.jsx', type: 'config', icon: Settings }
  ]

  const handleExport = async () => {
    setIsExporting(true)
    setExportProgress(0)
    
    try {
      // Create backup data structure
      const backupData = {
        metadata: {
          version: '1.0.0',
          timestamp: new Date().toISOString(),
          description: 'Complete site backup',
          totalFiles: pageFiles.length
        },
        files: {}
      }

      // Collect all file contents
      for (let i = 0; i < pageFiles.length; i++) {
        const file = pageFiles[i]
        setExportProgress(Math.round((i / pageFiles.length) * 100))
        
        try {
          // For demonstration, we'll create mock content
          // In a real implementation, you would fetch actual file content from the server
          if (file.type === 'folder') {
            backupData.files[file.name] = {
              type: 'folder',
              path: file.path,
              contents: 'Folder structure - would contain multiple files'
            }
          } else {
            backupData.files[file.name] = {
              type: file.type,
              path: file.path,
              contents: `// Content for ${file.name}\n// This would be the actual file content\n// Exported at ${new Date().toISOString()}`
            }
          }
        } catch (error) {
          console.warn(`Could not backup ${file.name}:`, error)
          backupData.files[file.name] = {
            type: file.type,
            path: file.path,
            error: 'File not accessible'
          }
        }
        
        // Small delay to show progress
        await new Promise(resolve => setTimeout(resolve, 100))
      }
      
      setExportProgress(100)
      
      // Create and download the backup file
      const backupBlob = new Blob([JSON.stringify(backupData, null, 2)], {
        type: 'application/json'
      })
      
      const url = URL.createObjectURL(backupBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `site-backup-${new Date().toISOString().split('T')[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
      
      toast.success('Site backup exported successfully!')
      
    } catch (error) {
      console.error('Export failed:', error)
      toast.error('Failed to export backup. Please try again.')
    } finally {
      setIsExporting(false)
      setExportProgress(0)
    }
  }

  const handleImport = async () => {
    if (!importFile) {
      toast.error('Please select a backup file to import')
      return
    }

    setIsImporting(true)
    setImportProgress(0)
    
    try {
      const fileContent = await importFile.text()
      const backupData = JSON.parse(fileContent)
      
      // Validate backup structure
      if (!backupData.metadata || !backupData.files) {
        throw new Error('Invalid backup file format')
      }
      
      setImportProgress(25)
      
      // Process each file in the backup
      const fileEntries = Object.entries(backupData.files)
      for (let i = 0; i < fileEntries.length; i++) {
        const [fileName, fileData] = fileEntries[i]
        setImportProgress(25 + Math.round((i / fileEntries.length) * 75))
        
        // In a real implementation, you would send this to your backend
        // to restore the files. For now, we'll just simulate the process
        console.log(`Restoring ${fileName}:`, fileData)
        
        // Small delay to show progress
        await new Promise(resolve => setTimeout(resolve, 50))
      }
      
      setImportProgress(100)
      toast.success('Site backup imported successfully!')
      setImportFile(null)
      
      // Reset file input
      const fileInput = document.getElementById('import-file-input')
      if (fileInput) {
        fileInput.value = ''
      }
      
    } catch (error) {
      console.error('Import failed:', error)
      toast.error('Failed to import backup. Please check the file format.')
    } finally {
      setIsImporting(false)
      setImportProgress(0)
    }
  }

  const handleDatabaseBackup = async () => {
    setIsDbExporting(true)
    
    try {
      // Simulate database backup process
      const dbBackupData = {
        metadata: {
          version: '1.0.0',
          timestamp: new Date().toISOString(),
          type: 'database',
          description: 'Database tables and records backup'
        },
        tables: {
          customers: {
            count: 150,
            lastBackup: new Date().toISOString(),
            records: 'Customer records would be exported here'
          },
          staff: {
            count: 12,
            lastBackup: new Date().toISOString(),
            records: 'Staff records would be exported here'
          },
          services: {
            count: 25,
            lastBackup: new Date().toISOString(),
            records: 'Service records would be exported here'
          },
          expenses: {
            count: 450,
            lastBackup: new Date().toISOString(),
            records: 'Expense records would be exported here'
          }
        }
      }

      // Simulate processing time
      await new Promise(resolve => setTimeout(resolve, 2000))

      // Create and download the database backup
      const backupBlob = new Blob([JSON.stringify(dbBackupData, null, 2)], {
        type: 'application/json'
      })
      
      const url = URL.createObjectURL(backupBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `database-backup-${new Date().toISOString().split('T')[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
      
      toast.success('Database backup exported successfully!')
      
    } catch (error) {
      console.error('Database backup failed:', error)
      toast.error('Failed to export database backup. Please try again.')
    } finally {
      setIsDbExporting(false)
    }
  }

  const handleSettingsBackup = async () => {
    setIsSettingsExporting(true)
    
    try {
      // Simulate settings backup process
      const settingsBackupData = {
        metadata: {
          version: '1.0.0',
          timestamp: new Date().toISOString(),
          type: 'settings',
          description: 'Application configuration settings backup'
        },
        settings: {
          general: {
            appName: 'Machinery Maintenance System',
            version: '1.0.0',
            theme: 'light',
            language: 'en'
          },
          database: {
            host: 'localhost',
            port: '5001',
            name: 'machinery_db'
          },
          api: {
            baseUrl: 'http://localhost:5001/api',
            timeout: 30000
          },
          ui: {
            itemsPerPage: 10,
            dateFormat: 'DD/MM/YYYY',
            currency: 'INR'
          }
        }
      }

      // Simulate processing time
      await new Promise(resolve => setTimeout(resolve, 1500))

      // Create and download the settings backup
      const backupBlob = new Blob([JSON.stringify(settingsBackupData, null, 2)], {
        type: 'application/json'
      })
      
      const url = URL.createObjectURL(backupBlob)
      const link = document.createElement('a')
      link.href = url
      link.download = `settings-backup-${new Date().toISOString().split('T')[0]}.json`
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
      
      toast.success('Settings backup exported successfully!')
      
    } catch (error) {
      console.error('Settings backup failed:', error)
      toast.error('Failed to export settings backup. Please try again.')
    } finally {
      setIsSettingsExporting(false)
    }
  }

  const handleFileSelect = (event) => {
    const file = event.target.files[0]
    if (file) {
      if (file.type === 'application/json' || file.name.endsWith('.json')) {
        setImportFile(file)
      } else {
        toast.error('Please select a valid JSON backup file')
      }
    }
  }

  const getFileIcon = (icon) => {
    const IconComponent = icon
    return <IconComponent className="h-4 w-4" />
  }

  const getTypeColor = (type) => {
    switch (type) {
      case 'page': return 'text-blue-600 bg-blue-50'
      case 'folder': return 'text-purple-600 bg-purple-50'
      case 'api': return 'text-green-600 bg-green-50'
      case 'config': return 'text-orange-600 bg-orange-50'
      default: return 'text-gray-600 bg-gray-50'
    }
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 flex items-center">
            <Archive className="h-6 w-6 mr-3 text-indigo-600" />
            Site Backup
          </h2>
          <p className="text-gray-600 mt-1">Export and import your complete site data</p>
        </div>
      </div>

      {/* Backup Info */}
      <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
        <div className="flex items-start">
          <AlertTriangle className="h-5 w-5 text-blue-600 mt-0.5 mr-3 flex-shrink-0" />
          <div>
            <h4 className="text-sm font-semibold text-blue-900">Backup Information</h4>
            <ul className="text-sm text-blue-800 mt-1 space-y-1">
              <li>· Export creates a complete backup of all page files and configurations</li>
              <li>· Import restores your site from a previously created backup</li>
              <li>· Always keep multiple backup copies for safety</li>
              <li>· Test imports on a development environment first</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Export Section */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-gray-900 flex items-center">
            <Download className="h-5 w-5 mr-2 text-green-600" />
            Export Backup
          </h3>
          <div className="text-sm text-gray-500">
            {pageFiles.length} files will be included
          </div>
        </div>

        <div className="space-y-4">
          <p className="text-gray-600">
            Create a complete backup of your site including all pages, components, and configuration files.
          </p>

          {/* Files to be exported */}
          <div className="bg-gray-50 rounded-lg p-4 max-h-60 overflow-y-auto">
            <h4 className="text-sm font-medium text-gray-700 mb-3">Files to be exported:</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
              {pageFiles.map((file, index) => (
                <div key={index} className="flex items-center space-x-2 text-sm">
                  <div className={`p-1 rounded ${getTypeColor(file.type)}`}>
                    {getFileIcon(file.icon)}
                  </div>
                  <span className="text-gray-700 truncate">{file.name}</span>
                  <span className="text-gray-400 text-xs">({file.type})</span>
                </div>
              ))}
            </div>
          </div>

          {/* Export Progress */}
          {isExporting && (
            <div className="space-y-2">
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-600">Exporting...</span>
                <span className="text-gray-900 font-medium">{exportProgress}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-green-600 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${exportProgress}%` }}
                ></div>
              </div>
            </div>
          )}

          {/* Export Button */}
          <button
            onClick={handleExport}
            disabled={isExporting}
            className="w-full md:w-auto px-6 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors flex items-center justify-center space-x-2"
          >
            {isExporting ? (
              <>
                <RefreshCw className="h-4 w-4 animate-spin" />
                <span>Exporting...</span>
              </>
            ) : (
              <>
                <Download className="h-4 w-4" />
                <span>Export Complete Backup</span>
              </>
            )}
          </button>
        </div>
      </div>

      {/* Import Section */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-lg font-semibold text-gray-900 flex items-center">
            <Upload className="h-5 w-5 mr-2 text-blue-600" />
            Import Backup
          </h3>
        </div>

        <div className="space-y-4">
          <p className="text-gray-600">
            Restore your site from a previously created backup file. This will replace current data.
          </p>

          {/* File Selection */}
          <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center">
            <input
              id="import-file-input"
              type="file"
              accept=".json"
              onChange={handleFileSelect}
              className="hidden"
            />
            <FolderOpen className="h-12 w-12 text-gray-400 mx-auto mb-3" />
            <label
              htmlFor="import-file-input"
              className="cursor-pointer inline-flex items-center px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
            >
              <Upload className="h-4 w-4 mr-2" />
              Select Backup File
            </label>
            <p className="text-sm text-gray-500 mt-2">
              Select a .json backup file to restore
            </p>
            {importFile && (
              <div className="mt-3 text-sm text-gray-700">
                <CheckCircle className="h-4 w-4 text-green-600 inline mr-1" />
                Selected: {importFile.name}
              </div>
            )}
          </div>

          {/* Import Progress */}
          {isImporting && (
            <div className="space-y-2">
              <div className="flex items-center justify-between text-sm">
                <span className="text-gray-600">Importing...</span>
                <span className="text-gray-900 font-medium">{importProgress}%</span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-blue-600 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${importProgress}%` }}
                ></div>
              </div>
            </div>
          )}

          {/* Import Button */}
          <button
            onClick={handleImport}
            disabled={!importFile || isImporting}
            className="w-full md:w-auto px-6 py-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors flex items-center justify-center space-x-2"
          >
            {isImporting ? (
              <>
                <RefreshCw className="h-4 w-4 animate-spin" />
                <span>Importing...</span>
              </>
            ) : (
              <>
                <Upload className="h-4 w-4" />
                <span>Import Backup</span>
              </>
            )}
          </button>
        </div>
      </div>

      {/* Additional Options */}
      <div className="bg-white rounded-lg border border-gray-200 p-6">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Additional Options</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <button 
            onClick={handleDatabaseBackup}
            disabled={isDbExporting}
            className="p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors text-left disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <div className="flex items-center justify-between mb-2">
              <Database className="h-6 w-6 text-purple-600" />
              {isDbExporting && <RefreshCw className="h-4 w-4 text-purple-600 animate-spin" />}
            </div>
            <h4 className="font-medium text-gray-900">Database Backup</h4>
            <p className="text-sm text-gray-600">Export database tables and records</p>
            {isDbExporting && (
              <div className="mt-2">
                <div className="w-full bg-gray-200 rounded-full h-1.5">
                  <div className="bg-purple-600 h-1.5 rounded-full animate-pulse" style={{ width: '60%' }}></div>
                </div>
                <p className="text-xs text-purple-600 mt-1">Exporting database...</p>
              </div>
            )}
          </button>
          <button 
            onClick={handleSettingsBackup}
            disabled={isSettingsExporting}
            className="p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition-colors text-left disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <div className="flex items-center justify-between mb-2">
              <FileText className="h-6 w-6 text-orange-600" />
              {isSettingsExporting && <RefreshCw className="h-4 w-4 text-orange-600 animate-spin" />}
            </div>
            <h4 className="font-medium text-gray-900">Settings Backup</h4>
            <p className="text-sm text-gray-600">Export only configuration settings</p>
            {isSettingsExporting && (
              <div className="mt-2">
                <div className="w-full bg-gray-200 rounded-full h-1.5">
                  <div className="bg-orange-600 h-1.5 rounded-full animate-pulse" style={{ width: '80%' }}></div>
                </div>
                <p className="text-xs text-orange-600 mt-1">Exporting settings...</p>
              </div>
            )}
          </button>
        </div>
      </div>
    </div>
  )
}

export default SiteBackup
