import React, { useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import Expense from './Expense'
import ServicesWrapper from './ServicesWrapper'
import StockManagementWrapper from './StockManagementWrapper'
import AssignedStaff from './AssignedStaff'
import SiteBackup from './SiteBackup'
import UserManagement from './UserManagement'
import { Package, IndianRupee, Settings as SettingsIcon, TrendingUp, Wrench, Users, Archive, Shield } from 'lucide-react'

const Settings = () => {
  const [searchParams] = useSearchParams()
  const activeTab = searchParams.get('tab') || 'stock-management'

  const tabs = [
    { 
      id: 'stock-management', 
      name: 'Stock Management', 
      icon: Package, 
      component: StockManagementWrapper,
      color: 'green'
    },
    { 
      id: 'expense', 
      name: 'Expense', 
      icon: IndianRupee, 
      component: Expense,
      color: 'amber'
    },
    { 
      id: 'services', 
      name: 'Services', 
      icon: SettingsIcon, 
      component: ServicesWrapper,
      color: 'purple'
    },
    { 
      id: 'assigned-staff', 
      name: 'Assigned Staff', 
      icon: Users, 
      component: AssignedStaff,
      color: 'blue'
    },
    { 
      id: 'site-backup', 
      name: 'Site Backup', 
      icon: Archive, 
      component: SiteBackup,
      color: 'indigo'
    },
    { 
      id: 'user-management', 
      name: 'User Management', 
      icon: Shield, 
      component: UserManagement,
      color: 'cyan'
    }
  ]

  const ActiveComponent = tabs.find(tab => tab.id === activeTab)?.component || StockManagementWrapper

  return (
    <div className="p-6">
      
      
      {/* Tab Navigation */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 mb-8 overflow-hidden">
        <nav className="flex overflow-x-auto overflow-y-hidden">
          {tabs.map((tab) => {
            const Icon = tab.icon
            const isActive = activeTab === tab.id
            const getColorClasses = (color) => {
              switch (color) {
                case 'green':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-green-600 to-green-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-green-50 border-r border-gray-200'
                case 'amber':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-amber-600 to-amber-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-amber-50 border-r border-gray-200'
                case 'purple':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-purple-600 to-purple-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-purple-50 border-r border-gray-200'
                case 'blue':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
                case 'indigo':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-indigo-600 to-indigo-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-indigo-50 border-r border-gray-200'
                case 'cyan':
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-cyan-600 to-cyan-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-cyan-50 border-r border-gray-200'
                default:
                  return isActive 
                    ? 'text-white bg-gradient-to-r from-blue-600 to-blue-700 shadow-lg'
                    : 'text-gray-600 hover:text-gray-900 hover:bg-blue-50 border-r border-gray-200'
              }
            }
            
            return (
              <a
                key={tab.id}
                href={`/settings?tab=${tab.id}`}
                onClick={(e) => {
                  e.preventDefault()
                  window.history.pushState({}, '', `/settings?tab=${tab.id}`)
                  window.dispatchEvent(new PopStateEvent('popstate'))
                }}
                className={`group relative flex items-center flex-shrink-0 px-6 py-4 text-sm font-medium transition-all duration-200 ${getColorClasses(tab.color)}`}
              >
                <div className="relative z-20 flex items-center">
                  <Icon className={`mr-3 h-5 w-5 transition-colors duration-200 ${
                    isActive ? 'text-white' : 'text-gray-400 group-hover:text-gray-600'
                  }`} />
                  <span className="relative z-20">{tab.name}</span>
                </div>
                {isActive && (
                  <div className={`absolute inset-0 bg-gradient-to-r ${
                    tab.color === 'green' ? 'from-green-600 to-emerald-600' :
                    tab.color === 'amber' ? 'from-amber-600 to-orange-600' :
                    tab.color === 'purple' ? 'from-purple-600 to-pink-600' :
                    tab.color === 'blue' ? 'from-blue-600 to-indigo-600' :
                    tab.color === 'indigo' ? 'from-indigo-600 to-purple-600' :
                    tab.color === 'cyan' ? 'from-cyan-600 to-teal-600' :
                    'from-blue-600 to-purple-600'
                  }`}></div>
                )}
                {!isActive && (
                  <div className={`absolute bottom-0 left-0 right-0 h-0.5 bg-gradient-to-r ${
                    tab.color === 'green' ? 'from-green-500 to-emerald-500' :
                    tab.color === 'amber' ? 'from-amber-500 to-orange-500' :
                    tab.color === 'purple' ? 'from-purple-500 to-pink-500' :
                    tab.color === 'blue' ? 'from-blue-500 to-indigo-500' :
                    tab.color === 'indigo' ? 'from-indigo-500 to-purple-500' :
                    tab.color === 'cyan' ? 'from-cyan-500 to-teal-500' :
                    'from-blue-500 to-purple-500'
                  } transform scale-x-0 group-hover:scale-x-100 transition-transform duration-200`}></div>
                )}
              </a>
            )
          })}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 min-h-[600px]">
        <ActiveComponent />
      </div>
    </div>
  )
}

export default Settings
