import React, { useState, useEffect } from 'react'
import { TrendingUp, TrendingDown, Calendar, Filter, Download, FileText, IndianRupee, Receipt, ArrowUpRight, ArrowDownRight, BarChart3, PieChart, Scale } from 'lucide-react'

const BalanceSheet = () => {
  const [bills, setBills] = useState([])
  const [expenses, setExpenses] = useState([])
  const [loading, setLoading] = useState(true)
  const [filters, setFilters] = useState({
    startDate: '',
    endDate: '',
    period: 'month' // week, month, quarter, year
  })
  const [viewMode, setViewMode] = useState('summary') // summary, detailed, charts

  useEffect(() => {
    fetchData()
  }, [filters])

  const fetchData = async () => {
    setLoading(true)
    try {
      // Fetch bills (income)
      const billParams = new URLSearchParams()
      if (filters.startDate) billParams.append('startDate', filters.startDate)
      if (filters.endDate) billParams.append('endDate', filters.endDate)
      
      const billsResponse = await fetch(`http://localhost:5001/api/bills?${billParams}`)
      const billsData = await billsResponse.json()
      
      // Fetch expenses
      const expenseParams = new URLSearchParams()
      if (filters.startDate) expenseParams.append('startDate', filters.startDate)
      if (filters.endDate) expenseParams.append('endDate', filters.endDate)
      
      const response = await fetch('http://localhost:5001/api/expense-categories')
      const expensesData = await response.json()
      
      setBills(billsData)
      setExpenses(expensesData)
    } catch (error) {
      console.error('Error fetching data:', error)
    } finally {
      setLoading(false)
    }
  }

  const calculateTotals = () => {
    const totalIncome = bills.reduce((sum, bill) => sum + (bill.grandTotal || 0), 0)
    const totalExpenses = expenses.reduce((sum, expense) => sum + (expense.amount || 0), 0)
    const netBalance = totalIncome - totalExpenses
    
    return {
      totalIncome,
      totalExpenses,
      netBalance,
      totalBills: bills.length,
      totalExpensesCount: expenses.length
    }
  }

  const getMonthlyData = () => {
    const monthlyData = {}
    const currentYear = new Date().getFullYear()
    
    // Initialize all months
    for (let i = 1; i <= 12; i++) {
      monthlyData[i] = {
        month: new Date(currentYear, i - 1).toLocaleDateString('en', { month: 'short' }),
        income: 0,
        expenses: 0,
        balance: 0
      }
    }
    
    // Add bills data
    bills.forEach(bill => {
      const date = new Date(bill.billDate)
      const month = date.getMonth() + 1
      if (monthlyData[month]) {
        monthlyData[month].income += bill.grandTotal || 0
      }
    })
    
    // Add expenses data
    expenses.forEach(expense => {
      const date = new Date(expense.date)
      const month = date.getMonth() + 1
      if (monthlyData[month]) {
        monthlyData[month].expenses += expense.amount || 0
      }
    })
    
    // Calculate balance
    Object.values(monthlyData).forEach(data => {
      data.balance = data.income - data.expenses
    })
    
    return Object.values(monthlyData)
  }

  const getCategoryBreakdown = () => {
    const categoryData = {}
    
    expenses.forEach(expense => {
      const categoryName = typeof expense.categoryId === 'object' 
        ? expense.categoryId.categoryName 
        : 'Unknown'
      
      if (!categoryData[categoryName]) {
        categoryData[categoryName] = {
          name: categoryName,
          amount: 0,
          count: 0
        }
      }
      
      categoryData[categoryName].amount += expense.amount || 0
      categoryData[categoryName].count += 1
    })
    
    return Object.values(categoryData).sort((a, b) => b.amount - a.amount)
  }

  const getPaymentMethodBreakdown = () => {
    const paymentData = {}
    
    // Bills payment methods
    bills.forEach(bill => {
      const method = bill.paymentMethod || 'cash'
      if (!paymentData[method]) {
        paymentData[method] = { name: method, income: 0, expenses: 0 }
      }
      paymentData[method].income += bill.grandTotal || 0
    })
    
    // Expenses payment methods
    expenses.forEach(expense => {
      const method = expense.paymentMethod || 'cash'
      if (!paymentData[method]) {
        paymentData[method] = { name: method, income: 0, expenses: 0 }
      }
      paymentData[method].expenses += expense.amount || 0
    })
    
    return Object.values(paymentData)
  }

  const setPeriodFilter = (period) => {
    const today = new Date()
    let startDate = ''
    let endDate = today.toISOString().split('T')[0]
    
    switch (period) {
      case 'week':
        const weekAgo = new Date(today.getTime() - 7 * 24 * 60 * 60 * 1000)
        startDate = weekAgo.toISOString().split('T')[0]
        break
      case 'month':
        const monthAgo = new Date(today.getFullYear(), today.getMonth(), 1)
        startDate = monthAgo.toISOString().split('T')[0]
        break
      case 'quarter':
        const quarterAgo = new Date(today.getFullYear(), today.getMonth() - 3, 1)
        startDate = quarterAgo.toISOString().split('T')[0]
        break
      case 'year':
        const yearAgo = new Date(today.getFullYear(), 0, 1)
        startDate = yearAgo.toISOString().split('T')[0]
        break
      default:
        startDate = ''
        endDate = ''
    }
    
    setFilters({ startDate, endDate, period })
  }

  const exportToCSV = () => {
    const totals = calculateTotals()
    const monthlyData = getMonthlyData()
    const categoryData = getCategoryBreakdown()
    
    let csv = 'Balance Sheet Report\n'
    csv += `Period: ${filters.startDate || 'All'} to ${filters.endDate || 'All'}\n\n`
    
    // Summary
    csv += 'Summary\n'
    csv += 'Total Income,Total Expenses,Net Balance\n'
    csv += `${totals.totalIncome.toFixed(2)},${totals.totalExpenses.toFixed(2)},${totals.netBalance.toFixed(2)}\n\n`
    
    // Monthly Data
    csv += 'Monthly Breakdown\n'
    csv += 'Month,Income,Expenses,Balance\n'
    monthlyData.forEach(month => {
      csv += `${month.month},${month.income.toFixed(2)},${month.expenses.toFixed(2)},${month.balance.toFixed(2)}\n`
    })
    
    // Category Breakdown
    csv += '\nExpense Categories\n'
    csv += 'Category,Amount,Count\n'
    categoryData.forEach(category => {
      csv += `${category.name},${category.amount.toFixed(2)},${category.count}\n`
    })
    
    // Download CSV
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `balance-sheet-${new Date().toISOString().split('T')[0]}.csv`
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    window.URL.revokeObjectURL(url)
  }

  const totals = calculateTotals()
  const monthlyData = getMonthlyData()
  const categoryData = getCategoryBreakdown()
  const paymentData = getPaymentMethodBreakdown()

  if (loading) {
    return (
      <div className="p-6 max-w-7xl mx-auto">
        <div className="flex justify-center items-center h-64">
          <div className="text-gray-500">Loading balance sheet data...</div>
        </div>
      </div>
    )
  }

  return (
    <div className="p-6 max-w-7xl mx-auto">
      {/* Header */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-gray-800">Balance Sheet</h1>
        <button
          onClick={exportToCSV}
          className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors"
        >
          <Download size={16} />
          Export CSV
        </button>
      </div>

      {/* Filters */}
      <div className="bg-white rounded-lg shadow p-4 mb-6">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Quick Period</label>
            <div className="flex gap-2">
              {['week', 'month', 'quarter', 'year'].map(period => (
                <button
                  key={period}
                  onClick={() => setPeriodFilter(period)}
                  className={`px-3 py-1 rounded-lg text-sm capitalize ${
                    filters.period === period
                      ? 'bg-blue-600 text-white'
                      : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                  }`}
                >
                  {period}
                </button>
              ))}
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
            <input
              type="date"
              value={filters.startDate}
              onChange={(e) => setFilters({ ...filters, startDate: e.target.value, period: 'custom' })}
              className="w-full border border-gray-300 rounded-lg px-3 py-2"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">End Date</label>
            <input
              type="date"
              value={filters.endDate}
              onChange={(e) => setFilters({ ...filters, endDate: e.target.value, period: 'custom' })}
              className="w-full border border-gray-300 rounded-lg px-3 py-2"
            />
          </div>
          <div className="flex items-end">
            <button
              onClick={() => setFilters({ startDate: '', endDate: '', period: 'month' })}
              className="w-full bg-gray-600 text-white px-4 py-2 rounded-lg hover:bg-gray-700 transition-colors"
            >
              Clear Filters
            </button>
          </div>
        </div>
      </div>

      {/* View Mode Tabs */}
      <div className="bg-white rounded-lg shadow mb-6">
        <div className="border-b border-gray-200">
          <nav className="flex space-x-8 px-6">
            {[
              { id: 'summary', name: 'Summary', icon: BarChart3 },
              { id: 'detailed', name: 'Detailed View', icon: FileText },
              { id: 'charts', name: 'Charts', icon: PieChart }
            ].map((tab) => {
              const Icon = tab.icon
              return (
                <button
                  key={tab.id}
                  onClick={() => setViewMode(tab.id)}
                  className={`py-4 px-1 border-b-2 font-medium text-sm flex items-center space-x-2 ${
                    viewMode === tab.id
                      ? 'border-blue-500 text-blue-600'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  }`}
                >
                  <Icon className="h-4 w-4" />
                  <span>{tab.name}</span>
                </button>
              )
            })}
          </nav>
        </div>
      </div>

      {/* Summary View */}
      {viewMode === 'summary' && (
        <div className="space-y-6">
          {/* Key Metrics */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Total Income</p>
                  <p className="text-2xl font-bold text-green-600">₹{totals.totalIncome.toFixed(2)}</p>
                  <p className="text-sm text-gray-500">{totals.totalBills} bills</p>
                </div>
                <div className="p-3 bg-green-100 rounded-lg">
                  <TrendingUp className="h-6 w-6 text-green-600" />
                </div>
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Total Expenses</p>
                  <p className="text-2xl font-bold text-red-600">₹{totals.totalExpenses.toFixed(2)}</p>
                  <p className="text-sm text-gray-500">{totals.totalExpensesCount} expenses</p>
                </div>
                <div className="p-3 bg-red-100 rounded-lg">
                  <TrendingDown className="h-6 w-6 text-red-600" />
                </div>
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Net Balance</p>
                  <p className={`text-2xl font-bold ${totals.netBalance >= 0 ? 'text-blue-600' : 'text-red-600'}`}>
                    ₹{totals.netBalance.toFixed(2)}
                  </p>
                  <p className="text-sm text-gray-500">Profit/Loss</p>
                </div>
                <div className={`p-3 rounded-lg ${totals.netBalance >= 0 ? 'bg-blue-100' : 'bg-red-100'}`}>
                  {totals.netBalance >= 0 ? (
                    <ArrowUpRight className="h-6 w-6 text-blue-600" />
                  ) : (
                    <ArrowDownRight className="h-6 w-6 text-red-600" />
                  )}
                </div>
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Average Bill</p>
                  <p className="text-2xl font-bold text-purple-600">
                    ₹{totals.totalBills > 0 ? (totals.totalIncome / totals.totalBills).toFixed(2) : '0.00'}
                  </p>
                  <p className="text-sm text-gray-500">Per transaction</p>
                </div>
                <div className="p-3 bg-purple-100 rounded-lg">
                  <Receipt className="h-6 w-6 text-purple-600" />
                </div>
              </div>
            </div>
          </div>

          {/* Monthly Trend */}
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-800 mb-4">Monthly Trend</h3>
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="border border-gray-200 px-4 py-2 text-left">Month</th>
                    <th className="border border-gray-200 px-4 py-2 text-right">Income</th>
                    <th className="border border-gray-200 px-4 py-2 text-right">Expenses</th>
                    <th className="border border-gray-200 px-4 py-2 text-right">Balance</th>
                  </tr>
                </thead>
                <tbody>
                  {monthlyData.map((month, index) => (
                    <tr key={index} className="hover:bg-gray-50">
                      <td className="border border-gray-200 px-4 py-2 font-medium">{month.month}</td>
                      <td className="border border-gray-200 px-4 py-2 text-right text-green-600">
                        ₹{month.income.toFixed(2)}
                      </td>
                      <td className="border border-gray-200 px-4 py-2 text-right text-red-600">
                        ₹{month.expenses.toFixed(2)}
                      </td>
                      <td className={`border border-gray-200 px-4 py-2 text-right font-medium ${
                        month.balance >= 0 ? 'text-blue-600' : 'text-red-600'
                      }`}>
                        ₹{month.balance.toFixed(2)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          {/* Top Expense Categories */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Top Expense Categories</h3>
              <div className="space-y-3">
                {categoryData.slice(0, 5).map((category, index) => (
                  <div key={index} className="flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-red-100 rounded-full flex items-center justify-center text-sm font-medium text-red-600">
                        {index + 1}
                      </div>
                      <span className="font-medium">{category.name}</span>
                    </div>
                    <div className="text-right">
                      <p className="font-medium text-red-600">₹{category.amount.toFixed(2)}</p>
                      <p className="text-sm text-gray-500">{category.count} items</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Payment Methods</h3>
              <div className="space-y-3">
                {paymentData.map((method, index) => (
                  <div key={index} className="flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center text-sm font-medium text-blue-600">
                        {method.name.charAt(0).toUpperCase()}
                      </div>
                      <span className="font-medium capitalize">{method.name}</span>
                    </div>
                    <div className="text-right">
                      <p className="font-medium text-green-600">₹{method.income.toFixed(2)}</p>
                      <p className="font-medium text-red-600">₹{method.expenses.toFixed(2)}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Detailed View */}
      {viewMode === 'detailed' && (
        <div className="space-y-6">
          {/* Recent Bills */}
          <div className="bg-white rounded-lg shadow">
            <div className="p-4 border-b border-gray-200">
              <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                <Receipt className="h-5 w-5 text-green-600" />
                Recent Bills (Income)
              </h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="border border-gray-200 px-4 py-2 text-left">Bill No</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Date</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Customer</th>
                    <th className="border border-gray-200 px-4 py-2 text-right">Amount</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Status</th>
                  </tr>
                </thead>
                <tbody>
                  {bills.slice(0, 10).map((bill) => (
                    <tr key={bill._id} className="hover:bg-gray-50">
                      <td className="border border-gray-200 px-4 py-2 font-mono">{bill.billNo}</td>
                      <td className="border border-gray-200 px-4 py-2">{new Date(bill.billDate).toLocaleDateString()}</td>
                      <td className="border border-gray-200 px-4 py-2">
                        {typeof bill.customerId === 'object' ? bill.customerId.name : bill.customerName}
                      </td>
                      <td className="border border-gray-200 px-4 py-2 text-right font-medium text-green-600">
                        ₹{bill.grandTotal.toFixed(2)}
                      </td>
                      <td className="border border-gray-200 px-4 py-2">
                        <span className={`px-2 py-1 text-xs rounded-full ${
                          bill.status === 'paid' ? 'bg-green-100 text-green-800' :
                          bill.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                          'bg-red-100 text-red-800'
                        }`}>
                          {bill.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {bills.length === 0 && (
                <div className="p-8 text-center text-gray-500">No bills found</div>
              )}
            </div>
          </div>

          {/* Recent Expenses */}
          <div className="bg-white rounded-lg shadow">
            <div className="p-4 border-b border-gray-200">
              <h3 className="text-lg font-semibold text-gray-800 flex items-center gap-2">
                <IndianRupee className="h-5 w-5 text-red-600" />
                Recent Expenses
              </h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full border-collapse">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="border border-gray-200 px-4 py-2 text-left">Expense No</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Date</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Category</th>
                    <th className="border border-gray-200 px-4 py-2 text-right">Amount</th>
                    <th className="border border-gray-200 px-4 py-2 text-left">Status</th>
                  </tr>
                </thead>
                <tbody>
                  {expenses.slice(0, 10).map((expense) => (
                    <tr key={expense._id} className="hover:bg-gray-50">
                      <td className="border border-gray-200 px-4 py-2 font-mono">{expense.expenseNo}</td>
                      <td className="border border-gray-200 px-4 py-2">{new Date(expense.date).toLocaleDateString()}</td>
                      <td className="border border-gray-200 px-4 py-2">
                        {typeof expense.categoryId === 'object' 
                          ? expense.categoryId.categoryName 
                          : 'Unknown'
                        }
                      </td>
                      <td className="border border-gray-200 px-4 py-2 text-right font-medium text-red-600">
                        ₹{expense.amount.toFixed(2)}
                      </td>
                      <td className="border border-gray-200 px-4 py-2">
                        <span className={`px-2 py-1 text-xs rounded-full ${
                          expense.status === 'approved' ? 'bg-green-100 text-green-800' :
                          expense.status === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                          'bg-red-100 text-red-800'
                        }`}>
                          {expense.status}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
              {expenses.length === 0 && (
                <div className="p-8 text-center text-gray-500">No expenses found</div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Charts View */}
      {viewMode === 'charts' && (
        <div className="space-y-6">
          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-800 mb-4">Financial Overview</h3>
            <div className="h-64 flex items-center justify-center text-gray-500">
              <div className="text-center">
                <PieChart className="h-16 w-16 mx-auto mb-4 text-gray-400" />
                <p>Chart visualization would be implemented here</p>
                <p className="text-sm">Consider integrating Chart.js or similar library</p>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-lg shadow p-6">
            <h3 className="text-lg font-semibold text-gray-800 mb-4">Monthly Comparison</h3>
            <div className="h-64 flex items-center justify-center text-gray-500">
              <div className="text-center">
                <BarChart3 className="h-16 w-16 mx-auto mb-4 text-gray-400" />
                <p>Bar chart visualization would be implemented here</p>
                <p className="text-sm">Showing income vs expenses by month</p>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default BalanceSheet
