import { Calendar, CheckCircle, Clock, AlertCircle, TrendingUp, Users, Gift } from 'lucide-react'
import { useNavigate } from 'react-router-dom'

const ReminderOverview = ({ reminderData }) => {
  const navigate = useNavigate()

  // Debug logging to check if data is being received
  console.log('=== REMINDER OVERVIEW COMPONENT DEBUG ===')
  console.log('Received reminderData:', reminderData)
  console.log('Total reminders:', reminderData.total)
  console.log('Applied reminders:', reminderData.applied)
  console.log('Pending reminders:', reminderData.pending)
  console.log('Completed reminders:', reminderData.completed)
  console.log('Today reminders:', reminderData.today)
  console.log('Overdue reminders:', reminderData.overdue)
  console.log('==========================================')

  const handleNavigate = (tab) => {
    navigate(`/reminder-management?tab=${tab}`)
  }

  const reminderCards = [
    {
      title: 'Total Reminders',
      count: reminderData.total || 0,
      icon: Calendar,
      color: 'blue',
      tab: 'reminders',
      description: 'All reminders'
    },
    {
      title: 'Applied',
      count: reminderData.applied || 0,
      icon: CheckCircle,
      color: 'green',
      tab: 'reminders',
      filter: 'applied',
      description: 'Successfully applied'
    },
    {
      title: 'Pending',
      count: reminderData.pending || 0,
      icon: Clock,
      color: 'yellow',
      tab: 'reminders',
      filter: 'pending',
      description: 'Awaiting action'
    },
    {
      title: 'Completed',
      count: reminderData.completed || 0,
      icon: TrendingUp,
      color: 'purple',
      tab: 'reminders',
      filter: 'completed',
      description: 'Finished tasks'
    },
    {
      title: 'Today',
      count: reminderData.today || 0,
      icon: Calendar,
      color: 'orange',
      tab: 'reminders',
      filter: 'today',
      description: 'Due today'
    },
    {
      title: 'Overdue',
      count: reminderData.overdue || 0,
      icon: AlertCircle,
      color: 'red',
      tab: 'reminders',
      filter: 'overdue',
      description: 'Past due date'
    },
    {
      title: 'Birthdays',
      count: reminderData.birthdays || 0,
      icon: Gift,
      color: 'pink',
      tab: 'reminders',
      filter: 'birthdays',
      description: 'Birthday reminders'
    }
  ]

  const getColorClasses = (color) => {
    switch (color) {
      case 'blue':
        return 'bg-gradient-to-br from-blue-900 to-blue-800 border-blue-700 hover:border-blue-500 hover:from-blue-800 hover:to-blue-700'
      case 'green':
        return 'bg-gradient-to-br from-green-900 to-green-800 border-green-700 hover:border-green-500 hover:from-green-800 hover:to-green-700'
      case 'yellow':
        return 'bg-gradient-to-br from-yellow-900 to-yellow-800 border-yellow-700 hover:border-yellow-500 hover:from-yellow-800 hover:to-yellow-700'
      case 'purple':
        return 'bg-gradient-to-br from-purple-900 to-purple-800 border-purple-700 hover:border-purple-500 hover:from-purple-800 hover:to-purple-700'
      case 'orange':
        return 'bg-gradient-to-br from-orange-900 to-orange-800 border-orange-700 hover:border-orange-500 hover:from-orange-800 hover:to-orange-700'
      case 'red':
        return 'bg-gradient-to-br from-red-900 to-red-800 border-red-700 hover:border-red-500 hover:from-red-800 hover:to-red-700'
      case 'pink':
        return 'bg-gradient-to-br from-pink-900 to-pink-800 border-pink-700 hover:border-pink-500 hover:from-pink-800 hover:to-pink-700'
      default:
        return 'bg-gradient-to-br from-gray-900 to-gray-800 border-gray-700 hover:border-gray-500 hover:from-gray-800 hover:to-gray-700'
    }
  }

  const getIconColor = (color) => {
    switch (color) {
      case 'blue': return 'text-blue-200'
      case 'green': return 'text-green-200'
      case 'yellow': return 'text-yellow-200'
      case 'purple': return 'text-purple-200'
      case 'orange': return 'text-orange-200'
      case 'red': return 'text-red-200'
      case 'pink': return 'text-pink-200'
      default: return 'text-gray-200'
    }
  }

  const getLightBackgroundClasses = (color) => {
    switch (color) {
      case 'blue': return 'bg-blue-50 border-blue-200 hover:bg-blue-100'
      case 'green': return 'bg-green-50 border-green-200 hover:bg-green-100'
      case 'yellow': return 'bg-yellow-50 border-yellow-200 hover:bg-yellow-100'
      case 'purple': return 'bg-purple-50 border-purple-200 hover:bg-purple-100'
      case 'orange': return 'bg-orange-50 border-orange-200 hover:bg-orange-100'
      case 'red': return 'bg-red-50 border-red-200 hover:bg-red-100'
      case 'pink': return 'bg-pink-50 border-pink-200 hover:bg-pink-100'
      default: return 'bg-gray-50 border-gray-200 hover:bg-gray-100'
    }
  }

  const getLightIconColor = (color) => {
    switch (color) {
      case 'blue': return 'text-blue-600'
      case 'green': return 'text-green-600'
      case 'yellow': return 'text-yellow-600'
      case 'purple': return 'text-purple-600'
      case 'orange': return 'text-orange-600'
      case 'red': return 'text-red-600'
      case 'pink': return 'text-pink-600'
      default: return 'text-gray-600'
    }
  }

  const getLightTextColor = (color) => {
    switch (color) {
      case 'blue': return 'text-blue-900'
      case 'green': return 'text-green-900'
      case 'yellow': return 'text-yellow-900'
      case 'purple': return 'text-purple-900'
      case 'orange': return 'text-orange-900'
      case 'red': return 'text-red-900'
      case 'pink': return 'text-pink-900'
      default: return 'text-gray-900'
    }
  }

  const getLightLabelColor = (color) => {
    switch (color) {
      case 'blue': return 'text-blue-600'
      case 'green': return 'text-green-600'
      case 'yellow': return 'text-yellow-600'
      case 'purple': return 'text-purple-600'
      case 'orange': return 'text-orange-600'
      case 'red': return 'text-red-600'
      case 'pink': return 'text-pink-600'
      default: return 'text-gray-600'
    }
  }

  return (
    <div>
      <h2 className="text-xl font-semibold text-gray-800 mb-4">Reminder Management</h2>
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-7 gap-4">
        {reminderCards.map((card, index) => {
          const Icon = card.icon
          return (
            <button
              key={index}
              onClick={() => handleNavigate(card.tab)}
              className={`group relative p-3 rounded-lg border shadow-sm transition-all duration-300 transform hover:-translate-y-1 hover:shadow-lg ${getColorClasses(card.color)}`}
              title={`View ${card.title} - ${card.description}`}
            >
              <div className="flex flex-col items-center text-center space-y-1">
                <div className={`w-6 h-6 rounded flex items-center justify-center ${getIconColor(card.color)}`}>
                  <Icon className="h-3 w-3" />
                </div>
                <div className="flex-1">
                  <p className="text-lg font-bold text-white">{card.count}</p>
                  <p className="text-xs font-medium text-white/80">{card.title}</p>
                </div>
              </div>
              
              {/* Hover effect overlay */}
              <div className="absolute inset-0 bg-white/10 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
              
              {/* Subtle pulse effect for overdue items */}
              {card.color === 'red' && card.count > 0 && (
                <div className="absolute top-2 right-2 w-2 h-2 bg-red-400 rounded-full animate-pulse"></div>
              )}
            </button>
          )
        })}
      </div>
      
      {/* Summary Section */}
      <div className="mt-6 bg-gradient-to-r from-indigo-50 to-purple-50 rounded-lg p-4 border border-indigo-200">
        <div className="flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-indigo-100 rounded-lg flex items-center justify-center">
              <Calendar className="h-5 w-5 text-indigo-600" />
            </div>
            <div>
              <h3 className="text-sm font-semibold text-indigo-900">Reminder Summary</h3>
              <p className="text-xs text-indigo-700">
                {reminderData.overdue > 0 ? (
                  <span className="text-red-600 font-medium">
                    {reminderData.overdue} overdue item{reminderData.overdue > 1 ? 's' : ''} require immediate attention
                  </span>
                ) : reminderData.today > 0 ? (
                  <span className="text-orange-600 font-medium">
                    {reminderData.today} reminder{reminderData.today > 1 ? 's' : ''} due today
                  </span>
                ) : (
                  <span className="text-green-600 font-medium">
                    All reminders are up to date
                  </span>
                )}
              </p>
            </div>
          </div>
          <button
            onClick={() => handleNavigate('reminders')}
            className="px-4 py-2 bg-indigo-600 text-white text-sm rounded-lg hover:bg-indigo-700 transition-colors flex items-center gap-2"
          >
            <Calendar className="h-4 w-4" />
            Manage All
          </button>
        </div>
      </div>
    </div>
  )
}

export default ReminderOverview
