  // Save bill
  const saveBill = async () => {
    if (!selectedCustomer || billItems.length === 0) {
      toast.error('Please select a customer and add at least one service')
      return
    }

    // Validate stock availability before saving
    const stockValidation = billItems.map(item => {
      if (item.category && item.subCategory && item.totalCount > 0) {
        const stockInfo = checkStockAvailability(item.category, item.subCategory, item.totalCount)
        return {
          category: item.category,
          subCategory: item.subCategory,
          requested: item.totalCount,
          available: stockInfo.available,
          isOverStock: stockInfo.isOverStock
        }
      }
      return null
    }).filter(Boolean)

    const overStockItems = stockValidation.filter(validation => validation.isOverStock)
    if (overStockItems.length > 0) {
      const errorMessage = overStockItems.map(item => 
        `${item.category} - ${item.subCategory}: Requested ${item.requested}, Available ${item.available}`
      ).join('\n')
      toast.error(`Insufficient stock:\n${errorMessage}`)
      return
    }

    try {
      const billData = {
        billNo,
        customerId: selectedCustomer._id,
        customerName: selectedCustomer.name,
        customerAddress: selectedCustomer.address,
        billDate,
        subtotal,
        serviceCharges,
        discount,
        grandTotal,
        paymentMethod,
        transactionNo,
        upiId,
        notes,
        customerType,
        items: billItems.map(item => ({
          serviceId: item.serviceId || null, // Allow null for stock billing
          subServiceId: item.subServiceId || null, // Allow null for stock billing
          serviceName: item.serviceName || (item.category && item.subCategory ? `${item.category} - ${item.subCategory}` : 'Unknown Service'),
          subServiceName: item.subServiceName || (item.category && item.subCategory ? item.subCategory : 'Unknown Item'),
          quantity: item.quantity || (item.totalCount || 1), // Use totalCount for stock billing
          unitPrice: item.unitPrice,
          unit: item.unit || 'unit',
          amount: item.total,
          // New stock detail fields
          category: item.category || '',
          subCategory: item.subCategory || '',
          totalStock: item.totalStock || 0,
          // New counting fields
          sheetCount: item.sheetCount || 0,
          wastCount: item.wastCount || 0,
          totalCount: item.totalCount || 0,
          // New text field
          text: item.text || ''
        }))
      }

      try {
        const response = editingBill 
          ? await billsAPI.update(editingBill._id, billData) 
          : await billsAPI.create(billData)

        if (response && response.data) {
          // Update stock management for new bills only (not edits to avoid double deduction)
          if (!editingBill) {
            updateStockManagement(billItems)
            toast.success('Bill saved and stock updated successfully!')
          } else {
            toast.success('Bill updated successfully!')
          }
          
          setShowBillingModal(false)
          resetBillingForm()
          setEditingBill(null)
          fetchBills()
        } else {
          toast.error('Error saving bill: No response data')
        }
      } catch (error) {
        console.error('Error saving bill:', error)
        toast.error('Error saving bill')
      }
    } catch (error) {
      console.error('Error saving bill:', error)
      toast.error('Error saving bill')
    }
  }

